from qiskit import QuantumCircuit
import matplotlib

def build():
    qc = QuantumCircuit(2)
    qc.h(0)
    qc.cx(0, 1)
    return qc

def is_fig(x):
    return isinstance(x, matplotlib.figure.Figure)

evidence = {}
proven = []

# A: output='mpl'
try:
    r = build().draw(output="mpl")
    ok = is_fig(r)
    evidence["A"] = f"draw(output='mpl') -> {type(r).__name__}; is Figure={ok}"
    if ok:
        proven.append("A")
except Exception as e:
    evidence["A"] = f"raised {type(e).__name__}: {str(e)[:90]}"

# B: output='figure'
try:
    r = build().draw(output="figure")
    ok = is_fig(r)
    evidence["B"] = f"draw(output='figure') -> {type(r).__name__}; is Figure={ok}"
    if ok:
        proven.append("B")
except Exception as e:
    evidence["B"] = f"raised {type(e).__name__}: {str(e)[:90]}"

# C: matplotlib + interactive flag
try:
    r = build().draw(output="matplotlib", interactive=True)
    ok = is_fig(r)
    evidence["C"] = f"draw(output='matplotlib', interactive=True) -> {type(r).__name__}; is Figure={ok}"
    if ok:
        proven.append("C")
except Exception as e:
    evidence["C"] = f"raised {type(e).__name__}: {str(e)[:90]}"

# D: premise that 'matplotlib' is a valid string
try:
    r = build().draw(output="matplotlib")
    ok = is_fig(r)
    evidence["D"] = f"draw(output='matplotlib') -> {type(r).__name__}; is Figure={ok} (D claims this string is valid)"
    if ok:
        proven.append("D")
except Exception as e:
    evidence["D"] = f"draw(output='matplotlib') raised {type(e).__name__}: {str(e)[:80]} -> D's premise is false"

emit_verdict({
    "answer": proven,
    "evidence": evidence,
    "observed": {"valid_mpl_string": "mpl"},
})
